-  int32_t const gridBlockIdx = blockIdx.x;
-  int32_t const gridThreadIdx = NumThreads * gridBlockIdx + threadIdx.x;
-  int32_t const numBlocks = gridDim.x;
-  int32_t const numThreadsPerGrid = numBlocks * NumThreads;
