+    if (laneIdx < topK) {
+      warpTopKScore[laneIdx] = warpTopKScore[laneIdx] / sum;
+    }
+  } else {
+    auto softmaxScore =
+        calcSoftmax(warp, laneIdx < topK ? warpTopKScore[laneIdx] : minScore, laneIdx, topK);
+    if (laneIdx < topK) {
+      warpTopKScore[laneIdx] = softmaxScore;
+    }
+  }
